#!/usr/bin/env bash
set -u

ROOT="./open-source/gnosis/distributed-inference"
LOG_DIR="$ROOT/probe-logs"
MONITOR_LOG="$LOG_DIR/big-llm-probe-monitor.log"
INTERVAL_SECONDS="${INTERVAL_SECONDS:-300}"

mkdir -p "$LOG_DIR"

probe_status() {
  local label="$1"
  local session="$2"
  local log_file="$3"

  local screen_state="missing"
  if screen -ls 2>/dev/null | grep -q "[.]$session[[:space:]]"; then
    screen_state="running"
  fi

  local verdict="pending"
  local progress="no log yet"
  if [[ -f "$log_file" ]]; then
    if grep -q '^PASS:' "$log_file"; then
      verdict="pass"
    elif grep -q '^FAIL:' "$log_file"; then
      verdict="fail"
    elif grep -q 'logits health' "$log_file"; then
      verdict="logits"
    elif grep -q 'loaded dense .knot' "$log_file"; then
      verdict="forwarding"
    else
      verdict="loading"
    fi

    progress="$(awk '
      /PASS:|FAIL:|rank 0:|gemma [0-9]+ layers:|^[[:space:]]+L[0-9]+:|^[[:space:]]+L[[:space:]]*[0-9]+\/|loaded dense \.knot|HTTP load/ {
        line=$0
      }
      END {
        if (line != "") print line
      }
    ' "$log_file")"
    if [[ -z "$progress" ]]; then
      progress="$(tail -n 1 "$log_file")"
    fi
  fi

  printf '%s | %-8s | screen=%-7s | verdict=%-10s | %s\n' \
    "$(date '+%Y-%m-%d %H:%M:%S %Z')" "$label" "$screen_state" "$verdict" "$progress"
}

while true; do
  {
    probe_status "gemma4" "gemma4_probe" "$LOG_DIR/gemma4-31b-it-probe.log"
    probe_status "qwen72" "qwen72_probe" "$LOG_DIR/qwen2.5-72b-probe.log"
    probe_status "llama70" "llama70_probe" "$LOG_DIR/llama-3.3-70b-probe.log"
    echo "---"
  } >> "$MONITOR_LOG"

  sleep "$INTERVAL_SECONDS"
done
